
import Vue from "vue";

import { PType, getTypeMatchup } from "@/types/ptype";


export default Vue.extend({
	name: "MatchupChartResult",

	props: {
		attackingType: {
			type: String as () => PType,
			required: true,
		},
		defendingType: {
			type: String as () => PType,
			required: true,
		},
	},

	computed: {
		result(): number {
			return getTypeMatchup(
				this.attackingType,
				this.defendingType,
			);
		},
	},
});
