
import Vue from "vue";

import { PType } from "@/types/ptype";
import toTitleCase from "@/utils/titleCase";


export default Vue.extend({
	props: {
		type: {
			type: String as () => PType,
			required: true,
		},
	},

	methods: {
		getTypeName(type: PType): string {
			return toTitleCase(type);
		},
	},
});
